```javascript
// web/src/components/SearchResults.js
import { VirtualList } from "./VirtualList.js";

export class SearchResults {
    constructor(container, searchEngine) {
        this.container = container;
        this.searchEngine = searchEngine;
        this.results = [];
        this.virtualList = null;
    }

    async search(query) {
        console.time("[SearchResults] Query execution");
        this.results = await this.searchEngine.search(query);
        console.timeEnd("[SearchResults] Query execution");

        console.log(`[SearchResults] Found ${this.results.length} results`);
        this.renderResults();
    }

    renderResults() {
        // Clear previous
        if (this.virtualList) {
            this.virtualList.destroy();
        }

        if (this.results.length === 0) {
            this.container.innerHTML = "<div class=\"no-results\">No results found</div>";
            return;
        }

        this.container.innerHTML = "";

        this.virtualList = new VirtualList({
            container: this.container,
            itemHeight: 80, // Fixed height for each result row
            totalCount: this.results.length,
            renderItem: (index) => this.renderResultItem(index),
            overscan: 5
        });
    }

    renderResultItem(index) {
        const result = this.results[index];

        const div = document.createElement("div");
        div.className = "search-result";
        div.dataset.id = result.id;
        div.dataset.index = index;

        div.innerHTML = `
            <div class="result-title">${escapeHtml(result.title)}</div>
            <div class="result-snippet">${highlightMatches(result.snippet)}</div>
            <div class="result-meta">
                <span class="result-agent">${result.agent}</span>
                <span class="result-date">${formatDate(result.created_at)}</span>
            </div>
        `;

        div.addEventListener("click", () => this.onResultClick(result));

        return div;
    }
}
