```javascript
// web/src/components/ConversationView.js
export class ConversationView {
    constructor(container) {
        this.container = container;
        this.messages = [];
        this.virtualList = null;
    }

    async loadConversation(conversationId) {
        console.time("[ConversationView] Load");
        this.messages = await this.db.loadConversation(conversationId);
        console.timeEnd("[ConversationView] Load");

        console.log(`[ConversationView] Loaded ${this.messages.length} messages`);
        this.render();
    }

    render() {
        if (this.virtualList) {
            this.virtualList.destroy();
        }

        // Variable height messages require different approach
        this.virtualList = new VariableHeightVirtualList({
            container: this.container,
            totalCount: this.messages.length,
            estimatedItemHeight: 120,
            renderItem: (index) => this.renderMessage(index),
            measureItem: (element) => element.offsetHeight
        });
    }

    renderMessage(index) {
        const msg = this.messages[index];

        const div = document.createElement("div");
        div.className = `message message-${msg.role}`;

        // Render markdown content
        div.innerHTML = `
            <div class="message-role">${msg.role}</div>
            <div class="message-content">${renderMarkdown(msg.content)}</div>
            <div class="message-time">${formatTime(msg.created_at)}</div>
        `;

        return div;
    }
}
